def extract_score(llm_output):
    try:
        score = float(llm_output.strip())
        return score
     except ValueError:
         return 0 
```

```py
def conditional_answer(x):
    relevance_score = extract_score(x['relevance_score'])
    if relevance_score &lt; 4:
        return "I don't know."
    else:
        return x['answer'] 
